const results = [];

for (const item of $input.all()) {
  const rows = item.json.rows || [];
  // Loop through each HTML string in the 'rows' array
  for (const rowHtml of rows) {

    // 1. SKIP HEADERS: If the row doesn't contain a <td>, it's likely a header (<th>), so we skip it.
    if (!rowHtml.includes('<td')) {
      continue;
    }

    // 2. EXTRACT NAME: 
    const nameMatch = rowHtml.match(/<td>(.*?)<\/td>/);
    let name = nameMatch ? nameMatch[1] : null;
    if (name) name = name.trim();

    // 3. EXTRACT URL:
    const urlMatch = rowHtml.match(/href="([^"]+)"/);
    let url = urlMatch ? urlMatch[1] : null;

    if (url?.startsWith('/')) {
      url = `https://www.swd.gov.hk${url}`;
    }

    results.push({
      type: 'remuneration package review report',
      organisation: name,
      url
    });
  }
}

// Return the cleaned data
return [{json: {orgReportUrls: results}}];

